  isFullKeyboardVisible = signal(false);

  openFullKeyboard() {
    this.isFullKeyboardVisible.set(true);
  }

  closeFullKeyboard = () => {
    this.isFullKeyboardVisible.set(false);
    this.keyboard?.destroy();
    console.log('keyboard destroyed');
  };

  currentFullKeyboardInput: HTMLInputElement | null = null;
  keyboard: Keyboard | null = null;

  triggerFullKeyboard(inputSelector: string, selectorClass: string) {
    this.keyboard?.destroy();

    const input = document.querySelector<HTMLInputElement>(inputSelector);
    if (!input) {
      return;
    }
    console.log('init keyboard');
    this.currentFullKeyboardInput = input;
    input.focus();
    this.keyboard = new Keyboard(selectorClass, {
      onChange: (input) => {
        if (this.currentFullKeyboardInput) {
          this.currentFullKeyboardInput.value = input;
        }
      },
      onKeyPress: (button) => {
        console.log('Button pressed', button);
      },
    });

    this.openFullKeyboard();
    input.addEventListener('blur', () => {
      // if(this.keyboard?.keyboardDOM)
    });
  }
